    for line in p.read_text().splitlines():
        line=line.split('#')[0].strip()
        if not line: continue
        m=re.match(r'-r\s+(.+)', line)
        if m:
            load(pathlib.Path(p).parent/m.group(1).strip()); continue
        m=re.match(r'([A-Za-z0-9_.\-]+)(?:\[[^\]]*\])?==([^\s]+)', line)
        if m:
            seen[m.group(1).lower().replace('_','-')]=m.group(2)
load('requirements-dev.txt')
print(f"pinned packages (dev closure): {len(seen)}")
import subprocess
frozen={}
for l in open('/tmp/_frozen.txt'):
    l=l.strip()
    m=re.match(r'([A-Za-z0-9_.\-]+)==([^\s]+)', l)
    if m: frozen[m.group(1).lower().replace('_','-')]=m.group(2)
drift=[]
missing=[]
for name,ver in sorted(seen.items()):
    iv=frozen.get(name)
    if iv is None: missing.append(name)
    elif iv!=ver: drift.append((name,ver,iv))
print("\n=== DRIFT (pinned != installed) ===")
for n,pv,iv in drift: print(f"  {n}: pinned {pv}  installed {iv}")
print("\n=== MISSING (pinned, not installed) ===")
for n in missing: print(f"  {n}")
if not drift and not missing: print("  none — fully in sync")
